const list = Array.isArray($json.buffer_messages) ? $json.buffer_messages : ($json.buffer_messages ? [$json.buffer_messages] : []);
const parsed = list.map((x) => { try { return typeof x === 'string' ? JSON.parse(x) : x; } catch { return { text: String(x || '') }; } });
parsed.sort((a,b) => String(a.ts||'').localeCompare(String(b.ts||'')));
const merged = parsed.map((p) => p.text || '').filter(Boolean).join(' | ');
return { merged_message: merged || $('Normalize Input').item.json.incoming_text, merged_count: parsed.length || 1 };

let obj = {}; try { obj = JSON.parse($json.choices?.[0]?.message?.content || '{}'); } catch {}
const reply = obj.reply || 'Oi, posso te ajudar com ambiental, energia ou acionamento. Qual voce quer agora?';
const need_followup = !!obj.need_followup || $('Parse Orchestrator').item.json.need_followup;
const need_handoff = !!obj.need_handoff || $('Parse Orchestrator').item.json.need_handoff;
const delay = Math.min(12, Math.max(2, Math.ceil(String(reply).length / 28)));
return { assistant_reply: reply, need_followup, need_handoff, dynamic_delay_seconds: delay };
